#include <iostream>
#include <cstring>
#include <sys/socket.h>
#include <arpa/inet.h>
#include <unistd.h>

#define PORT 8080
#define BUFFER_SIZE 1024

struct Player {
    int id;
    float x, y, z;
};

void handleClient(int clientSocket) {
    char buffer[BUFFER_SIZE];
    ssize_t bytesRead;

    while ((bytesRead = recv(clientSocket, buffer, BUFFER_SIZE, 0)) > 0) {
        // Process the packet
        if (buffer[0] == 'P') { // Position update
            Player player;
            memcpy(&player, &buffer[1], sizeof(Player));
            std::cout << "Player " << player.id << " position: (" 
                      << player.x << ", " << player.y << ", " << player.z << ")" << std::endl;
        } else if (buffer[0] == 'S') { // Shooting action
            int shooterId = *(int*)&buffer[1];
            std::cout << "Player " << shooterId << " is shooting" << std::endl;
        }
    }

    close(clientSocket);
}

int main() {
    int serverSocket, clientSocket;
    struct sockaddr_in serverAddr, clientAddr;
    socklen_t addrLen = sizeof(clientAddr);

    // Create socket
    if ((serverSocket = socket(AF_INET, SOCK_DGRAM, 0)) < 0) {
        perror("socket creation failed");
        exit(EXIT_FAILURE);
    }

    memset(&serverAddr, 0, sizeof(serverAddr));
    serverAddr.sin_family = AF_INET;
    serverAddr.sin_addr.s_addr = INADDR_ANY;
    serverAddr.sin_port = htons(PORT);

    // Bind the socket
    if (bind(serverSocket, (const struct sockaddr *)&serverAddr, sizeof(serverAddr)) < 0) {
        perror("bind failed");
        close(serverSocket);
        exit(EXIT_FAILURE);
    }

    std::cout << "UDP Game Server is running on port " << PORT << std::endl;

    while (true) {
        clientSocket = accept(serverSocket, (struct sockaddr *)&clientAddr, &addrLen);
        if (clientSocket < 0) {
            perror("accept");
            continue;
        }

        handleClient(clientSocket);
    }

    close(serverSocket);
    return 0;
}